section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/error-budget-policy-and-freeze-rules.json",
  "type": "object",
  "required": [
    "policy_version",
    "doctrine_url",
    "authorised_declarers",
    "freeze_allow_list",
    "freeze_deny_list",
    "revert_criteria",
    "comms_channels",
    "review_date",
    "signoff"
  ],
  "properties": {
    "policy_version": {
      "type": "string",
      "description": "string (semver)"
    },
    "doctrine_url": {
      "type": "string",
      "description": "string"
    },
    "authorised_declarers": {
      "type": "array",
      "description": "array"
    },
    "freeze_allow_list": {
      "type": "array",
      "description": "array (e.g. security_patch, rollback, tier0_bugfix)"
    },
    "freeze_deny_list": {
      "type": "array",
      "description": "array"
    },
    "revert_criteria": {
      "type": "object",
      "description": "object (e.g. budget_remaining_min, burn_rate_max, duration_h)"
    },
    "comms_channels": {
      "type": "array",
      "description": "array (slack channel, email list)"
    },
    "review_date": {
      "type": "string",
      "description": "string"
    },
    "signoff": {
      "type": "object",
      "description": "object (engineering_leader, product_vp, date)"
    }
  }
}
